import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_cost(node_index):
        # Calculate distance from current position to next node
        dist = np.linalg.norm(np.array(cur_truck_pos) - np.array(unvisited_customers[node_index]))

        # Calculate waiting time at the node if needed
        if current_time < time_windows[node_index][0]:
            waiting_time = time_windows[node_index][0] - current_time
        else:
            waiting_time = 0

        # Calculate penalty for missing time window
        if current_time + (dist/truck_speed) + waiting_time > time_windows[node_index][1]:
            penalty = 1000  # Arbitrary large penalty for missing time window
        else:
            penalty = 0

        return dist/truck_speed + waiting_time + penalty

    best_cost = float('inf')
    best_node = None

    for i in range(len(unvisited_customers)):
        cost = calculate_cost(i)
        if cost < best_cost:
            best_cost = cost
            best_node = i

    return best_node

